SELECT sum(change_amount) as money
FROM ct_merchant_amount_records
WHERE user_id = #{userId}
  AND change_type = #{changeType}
  AND create_time >= #{startTime}
  AND create_time <= #{endTime}

SELECT a.*
FROM ct_merchant_amount_records a
JOIN ct_merchant b ON a.user_id = b.user_id


        and a.user_id = #{dto.userId}


        and a.user_name = #{dto.userName}


        and b.merchant_level = #{dto.merchantLevel}


        and a.amount_type = #{dto.amountType}




                and a.change_type = 2 and change_amount >= 0


                and a.change_type = 2 and change_amount < 0


                and a.change_type = #{dto.changeType}






        and a.create_time >= #{dto.startTime}


        and a.create_time <= #{dto.endTime}


        and a.order_no = #{dto.orderNo}


        AND b.parent_path like concat(#{dto.parentPath},'%')
